function o(){return typeof window<"u"&&!!window.electronAPI?.waStatus}function s(){return window.electronAPI}async function u(){if(o())return s().waStatus();const t=await fetch("/api/whatsapp/status");if(!t.ok)throw new Error("Failed to fetch WhatsApp status");return t.json()}async function f(){try{return(await u()).status==="connected"}catch{return!1}}async function w(){if(o()){await s().waInit();return}await fetch("/api/whatsapp/init",{method:"POST"})}async function d(){if(o()){await s().waLogout();return}await fetch("/api/whatsapp/logout",{method:"POST"})}async function l(t,n){try{if(o()){const a=await s().waSend({to:t,message:n});return a?.error?(console.warn("[WA] send error:",a.error),!1):!0}const e=await(await fetch("/api/whatsapp/send",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({to:t,message:n})})).json();return e.error?(console.warn("[WA] send error:",e.error),!1):!0}catch(r){return console.warn("[WA] send exception:",r),!1}}async function p(t,n,r,e=""){try{if(o()){const c=await s().waSendDoc({to:t,pdfBase64:n,filename:r,caption:e});return c?.error?(console.warn("[WA] send-doc error:",c.error),!1):!0}const i=await(await fetch("/api/whatsapp/send-doc",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({to:t,pdfBase64:n,filename:r,caption:e})})).json();return i.error?(console.warn("[WA] send-doc error:",i.error),!1):!0}catch(a){return console.warn("[WA] send-doc exception:",a),!1}}function h(t){if(!t)return null;const n=t.replace(/\D/g,"");return n.length<10?null:n.length===10?"91"+n:n}export{f as a,l as b,u as g,w as i,d as l,h as n,p as s};
